using Apex.Application.Abstractions.Data;using Apex.Application.Abstractions.Exceptions;using Apex.Application.Abstractions.Time;using Apex.Modules.Accounting.ChartOfAccounts.Domain;using Apex.Modules.Accounting.ChartOfAccounts.Repositories;using Microsoft.AspNetCore.Mvc;
namespace Apex.Modules.Accounting.ChartOfAccounts.UseCases.ReactivateAccountClass;
internal sealed class ReactivateAccountClassHandler(IGeneralTransactionRunner tx,IAccountClassWriteRepository repo,IClock clock){public async Task HandleAsync(long id,CancellationToken ct)=>await tx.ExecuteAsync(async token=>{var v=await repo.GetForUpdateAsync(id,token)??throw new NotFoundException("Account class was not found.",ChartOfAccountsErrors.AccountClassNotFound);v.Reactivate(clock.UtcNow);await repo.UpdateAsync(v,token);},ct);}
internal static class ReactivateAccountClassEndpoint{internal static RouteGroupBuilder MapReactivateAccountClassEndpoint(this RouteGroupBuilder g){g.MapPost("/classes/{id:long}/reactivate",async(long id,[FromServices]ReactivateAccountClassHandler h,CancellationToken ct)=>{await h.HandleAsync(id,ct);return Results.NoContent();}).WithName("ReactivateAccountClass");return g;}}
